    scwin.f_toExcel1 = function() {
        var rowCount = ds_retrieveLineType.getRowCount();
        if ( rowCount == 0 ) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
        }
        else {
                            //sheet명       , 저장파일명            , 저장 다이얼로그
            //cfGridToExcel(gr_retrieveLineType, "LINE_TYPE별 재고현황" , "LINE_TYPE별 재고현황.xls" , 4+8+16);

            var sheetTitle = "LINE_TYPE별 재고현황";
            const options = {
                fileName: sheetTitle + ".xlsx" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
                , sheetName: sheetTitle //엑셀내 시트명 지정필요시
            };

            const infoArr = [];
            $c.data.downloadGridViewExcel(gr_retrieveLineType, options, infoArr);
        }
    };

