	//-------------------------------------------------------------------------
    // 라인콤보 조회 
    //-------------------------------------------------------------------------
    scwin.f_setLine = function(){
	    //ds_LineList.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=LineEBC&queryId=retrieveLineEachShpCoCdCombo&param1=<%=loginClntNo%>&param2=<%=userClsCd%>&param3="+ed_shpCo.Text;
	    //ds_LineList.Reset();

        if(scwin.memJson.userId == "dwstms"){
            ds_LineList.removeAll();
            ds_LineList.insertRow(0);
            ds_LineList.setCellData(0,"code","");
            ds_LineList.setCellData(0,"name","-전체-");
            ds_LineList.setCellData(1,"code","TMSC");
            ds_LineList.setCellData(1,"name","DOOWOO SHIPPING CO.,LTD");
        }else{
            var jsonData = {
                sysCd  : "LineEBC"
                ,queryId : "retrieveLineEachShpCoCdCombo"
                ,param1 : scwin.loginClntNo
                ,param2 : scwin.userClsCd
                ,param3 : ed_shpCo.getValue()
            }

            ds_srchLine.setJSON(jsonData);
            $c.sbm.execute(sbm_line);
        }
    };

	//-------------------------------------------------------------------------
    // 상세 팝업 조회조건 세팅	 bran, cy, line, shpco, cntrTypCd, impExpClsCd, fullEmptyClsCd, cntrSizCd, gradeCls
    //-------------------------------------------------------------------------
    scwin.f_setArrParam = function(grId, row, colid, subTotFlg){
        scwin.arrParam = [];
    	if(grId == "gr_retrieveYardLineType") {
    		scwin.arrParam[1] = subTotFlg ? "" : ds_retrieveYardLineType.getCellData(row,"cy"); 		//작업장
			scwin.arrParam[4] = subTotFlg ? "" : ds_retrieveYardLineType.getCellData(row,"cntrTypCd");	//타입
    	}else if(grId == "gr_retrieveLineType") {
    		scwin.arrParam[1] = ds_oGDS_view_cond.get("cy"); 				//작업장
			scwin.arrParam[4] = subTotFlg ? "" : ds_retrieveLineType.getCellData(row,"cntrTypCd");	//타입
    	}else {
    		$c.win.alert("화면에러입니다.");
    		return false;
    	}

		scwin.arrParam[0] = ds_oGDS_view_cond.get("bran"); //점소
		scwin.arrParam[2] = ds_oGDS_view_cond.get("line"); //라인
		scwin.arrParam[3] = ds_oGDS_view_cond.get("shpCo"); //선사코드
		switch (colid)
		{
			case "impFull20":
				scwin.arrParam[5] = "I";
				scwin.arrParam[6] = "F";
				scwin.arrParam[7] = "20";
				scwin.arrParam[8] = "";
				break;
			case "impFull40":
				scwin.arrParam[5] = "I";
				scwin.arrParam[6] = "F";
				scwin.arrParam[7] = "40";
				scwin.arrParam[8] = "";
				break;
			case "impFull45":
				scwin.arrParam[5] = "I";
				scwin.arrParam[6] = "F";
				scwin.arrParam[7] = "45";
				scwin.arrParam[8] = "";
				break;
			case "impFullTeu":
				scwin.arrParam[5] = "I";
				scwin.arrParam[6] = "F";
				scwin.arrParam[7] = "";
				scwin.arrParam[8] = "";
				break;									
			case "expFull20":
				scwin.arrParam[5] = "O";
				scwin.arrParam[6] = "F";
				scwin.arrParam[7] = "20";
				scwin.arrParam[8] = "";
				break;
			case "expFull40":
				scwin.arrParam[5] = "O";
				scwin.arrParam[6] = "F";
				scwin.arrParam[7] = "40";
				scwin.arrParam[8] = "";
				break;
			case "expFull45":
				scwin.arrParam[5] = "O";
				scwin.arrParam[6] = "F";
				scwin.arrParam[7] = "45";
				scwin.arrParam[8] = "";
				break;
			case "expFullTeu":
				scwin.arrParam[5] = "O";
				scwin.arrParam[6] = "F";
				scwin.arrParam[7] = "";
				scwin.arrParam[8] = "";
				break;		
			case "empty20":
				scwin.arrParam[5] = "";
				scwin.arrParam[6] = "E";
				scwin.arrParam[7] = "20";
				scwin.arrParam[8] = "";
				break;
