scwin.sbm_retrieve_submitdone = async function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    var rowcnt = ds_retrieveLineType.getRowCount();
    tbx_totalRows.setValue(rowcnt);

    rowcnt = ds_retrieveYardLineType.getRowCount();
    tbx_totalRows2.setValue(rowcnt);

	if (rowcnt == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
	}else{
        //ds_retrieveLineType.sort("line", 2);   //정렬취소
        ds_retrieveLineType.sort("line", 0);   //오름차순
        ds_retrieveYardLineType.sort("line", 0); // 2차 정렬 먼저
        ds_retrieveYardLineType.sort("cyNm", 0); // 1차 정렬 나중에

    }

    gr_retrieveLineType.setFocusedCell(0, "line", false);
};

scwin.sbm_retrieve_submiterror = function(e) {

};

scwin.sbm_lobran_submitdone = function (e) {
    // 점소가 NULL이 아닐경우 넘어온 점소로 세팅함.
    if ( scwin.reqLobranCd != "" ) {
        for (var i=0; i<co_ds_LoBran.getRowCount(); i++) {
            if ( co_ds_LoBran.getCellData(i,"lobranCd") == scwin.reqLobranCd ) {
                //lc_con_bran.Index = (i-1);
                acb_con_bran.setValue(scwin.reqLobranCd);
                break;
            }
        }
    }else{
        if(scwin.userClsCd == "01"){  //사용자가 그룹사가 아닐때
            acb_con_bran.setValue(scwin.lobranCd);
        }
    }

    if (scwin.reqCy != "" ) {
        ed_con_cy.setValue(scwin.reqCy);
        ed_con_cy.hidVal = scwin.reqCy;
    }
    if (scwin.reqCyNm != "" ) {
        ed_con_cyNm.setValue(scwin.reqCyNm);
        ed_con_cyNm.hidVal = scwin.reqCyNm;
    }

    if (scwin.reqCy != "" ) {
        scwin.f_Retrieve();
    }
};

